import { Kernel } from "@semantic-kernel/core";
import { OpenAIChatCompletion } from "@semantic-kernel/connectors-ai-openai";

const kernel = Kernel.create({
  chat: {
    OpenAIChatCompletion({
      modelId: "gpt-4",
      apiKey: process.env.OPENAI_API_KEY,
    }),
  },
});

kernel.importPluginFromObject({
  lookupOrder: async (orderId: string): Promise<string> => {
    // CRM API call
    return `Order ${orderId}: Status: Shipped, ETA: 2024-01-20`;
  },
}, "OrderLookup");

const memoryStore = await kernel.addVolatileMemoryStore();

// Store past interaction
const memory = await memoryStore.createCollection("support_conversations", "#12345");
await memoryStore.upsert("chat_history", {
  content: "Customer asked about order delay yesterday",
  timestamp: new Date().toISOString()
});

// Retrieve relevant memories
const results = await memoryStore.search("support_conversations", {
  query: "order status",
  limit: 3,
  minRelevanceScore: 0.7
});

