import { Vex } from "vex-sdk";

const vex = new Vex({ apiKey: "vex-your-key" });

const suite = await vex.createSuite({
  name: "customer-support",
  verifications: [
    "response_accuracy",
    "pii_filtering",
    "tone_consistency",
    "policy_compliance",
    "escalation_triggers"
  ],
  riskProfile: "high"
});

// Wrap OrderLookup plugin
const safeOrderLookup = async (orderId: string): Promise<string> => {
  const rawResult = await kernel.invoke("OrderLookup", "lookupOrder", { orderId });

  const verdict = await suite.verify({
    input: `Order lookup for ${orderId}`,
    output: rawResult,
    context: { customerId: "12345" }
  });

  if (verdict.status === "fail") {
    throw new Error(`Vex verification failed: ${verdict.reason}`);
  }

  return rawResult as string;
};

kernel.importPluginFromObject({ safeOrderLookup }, "SafeOrderLookup");

from semantic_kernel.contents import ChatHistory

class VexPlanValidator:
    def __init__(self, vex_suite):
        self.suite = vex_suite

    def validate_plan(self, plan: SequentialPlan) -> bool:
        plan_steps = [step.name for step in plan._steps]

        verdict = self.suite.verify({
            "input": "Validate support plan",
            "output": plan_steps,
            "policy": "order_lookup_before_ticket_creation"
        })

        return verdict.status == "pass"

# Global plan validator
kernel.register_plan_validator(VexPlanValidator(suite))

